     1	//! SafeClaw - Secure Personal AI Assistant with TEE Support
     2	//!
     3	//! A privacy-focused personal AI assistant that combines multi-channel
     4	//! messaging capabilities with hardware-isolated execution for sensitive data.
     5	
     6	use anyhow::{Context, Result};
     7	use clap::{Parser, Subcommand};
     8	use safeclaw::{
     9	    agent::{AgentBus, AgentEngine, AgentSessionStore, AgentState},
    10	    api::build_app,
    11	    audit::AuditState,
    12	    config::{
    13	        ChannelsConfig, DingTalkConfig, DiscordConfig, FeishuConfig, SafeClawConfig, ServerConfig,
    14	        SlackConfig, TeeBackend, TeeConfig, TelegramConfig, WeComConfig, WebChatConfig,
    15	    },
    16	    privacy::handler::PrivacyState,
    17	    runtime::RuntimeBuilder,
    18	};
    19	use std::io::{self, BufRead, Write};
    20	use std::path::PathBuf;
    21	use tracing_subscriber::{layer::SubscriberExt, util::SubscriberInitExt};
    22	
    23	#[derive(Parser)]
    24	#[command(name = "safeclaw")]
    25	#[command(author = "A3S Lab Team")]
    26	#[command(version)]
    27	#[command(about = "Secure Personal AI Assistant with TEE Support")]
    28	struct Cli {
    29	    /// Configuration file path (.hcl)
    30	    #[arg(short, long, env = "SAFECLAW_CONFIG")]
    31	    config: Option<PathBuf>,
    32	
    33	    /// Enable verbose logging
    34	    #[arg(short, long)]
    35	    verbose: bool,
    36	
    37	    #[command(subcommand)]
    38	    command: Commands,
    39	}
    40	
    41	#[derive(Subcommand)]
    42	enum Commands {
    43	    /// Start the SafeClaw gateway
    44	    Gateway {
    45	        /// Host to bind to
    46	        #[arg(long, default_value = "127.0.0.1")]
    47	        host: String,
    48	
    49	        /// Port to listen on
    50	        #[arg(long, default_value = "18790")]
    51	        port: u16,
    52	
    53	        /// Disable TEE mode
    54	        #[arg(long)]
    55	        no_tee: bool,
    56	    },
    57	
    58	    /// Start SafeClaw as a backend service (behind a3s-gateway)
    59	    Serve {
    60	        /// Host to bind to
    61	        #[arg(long, default_value = "127.0.0.1")]
    62	        host: String,
    63	
    64	        /// Port to listen on
    65	        #[arg(long, default_value = "18790")]
    66	        port: u16,
    67	
    68	        /// Disable TEE mode
    69	        #[arg(long)]
    70	        no_tee: bool,
    71	    },
    72	
    73	    /// Generate a3s-gateway routing configuration for SafeClaw
    74	    ServerConfig {
    75	        /// Output file path (stdout if not specified)
    76	        #[arg(short, long)]
    77	        output: Option<std::path::PathBuf>,
    78	    },
    79	
    80	    /// Run the onboarding wizard
    81	    Onboard {
    82	        /// Install as system daemon
    83	        #[arg(long)]
    84	        install_daemon: bool,
    85	    },
    86	
    87	    /// Send a message
    88	    Message {
    89	        /// Target channel
    90	        #[arg(short, long)]
    91	        channel: String,
    92	
    93	        /// Target chat ID
    94	        #[arg(short = 't', long)]
    95	        to: String,
    96	
    97	        /// Message content
    98	        #[arg(short, long)]
    99	        message: String,
   100	
   101	        /// Gateway URL to connect to
   102	        #[arg(long, default_value = "http://127.0.0.1:18790")]
   103	        gateway_url: String,
   104	    },
   105	
   106	    /// Run diagnostics
   107	    Doctor,
   108	
   109	    /// Show configuration
   110	    Config {
   111	        /// Show default configuration
   112	        #[arg(long)]
   113	        default: bool,
   114	    },
   115	
   116	    /// Update safeclaw to the latest version
   117	    Update,
   118	}
   119	
   120	/// Walk up from the current directory looking for `.a3s/config.hcl`.
   121	///
   122	/// This mirrors how `git` finds `.git` вҖ” works regardless of which
   123	/// subdirectory the binary is run from inside the monorepo.
   124	fn find_a3s_config() -> Option<std::path::PathBuf> {
   125	    let mut dir = std::env::current_dir().ok()?;
   126	    loop {
   127	        let candidate = dir.join(".a3s/config.hcl");
   128	        if candidate.exists() {
   129	            return Some(candidate);
   130	        }
   131	        if !dir.pop() {
   132	            return None;
   133	        }
   134	    }
   135	}
   136	
   137	#[tokio::main]
   138	async fn main() -> Result<()> {
   139	    let cli = Cli::parse();
   140	
   141	    // Apply OS-level hardening before loading any secrets
   142	    if let Err(e) = safeclaw::hardening::harden_process() {
   143	        eprintln!("Warning: process hardening failed: {}", e);
   144	    }
   145	
   146	    // Initialize logging
   147	    let log_level = if cli.verbose { "debug" } else { "info" };
   148	    tracing_subscriber::registry()
   149	        .with(
   150	            tracing_subscriber::EnvFilter::try_from_default_env()
   151	                .unwrap_or_else(|_| format!("safeclaw={},tower_http=debug", log_level).into()),
   152	        )
   153	        .with(tracing_subscriber::fmt::layer())
   154	        .init();
   155	
   156	    // Load configuration
   157	    // Priority: -c flag > ./safeclaw.hcl > <ancestor>/.a3s/config.hcl > ~/.config/safeclaw/config.hcl > default
   158	    // Model config (.a3s/config.hcl) is always merged in if the primary config has no providers.
   159	    let (mut config, config_path): (SafeClawConfig, Option<std::path::PathBuf>) =
   160	        if let Some(config_path) = cli.config {
   161	            let content = std::fs::read_to_string(&config_path)?;
   162	            tracing::info!("Loading config from {}", config_path.display());
   163	            (SafeClawConfig::from_hcl(&content)?, Some(config_path))
   164	        } else if std::path::Path::new("safeclaw.hcl").exists() {
   165	            let content = std::fs::read_to_string("safeclaw.hcl")?;
   166	            tracing::info!("Loading config from ./safeclaw.hcl");
   167	            (
   168	                SafeClawConfig::from_hcl(&content)?,
   169	                Some(std::path::PathBuf::from("safeclaw.hcl")),
   170	            )
   171	        } else if let Some(a3s_config) = find_a3s_config() {
   172	            let content = std::fs::read_to_string(&a3s_config)?;
   173	            tracing::info!("Loading config from {}", a3s_config.display());
   174	            let code_config = a3s_code::config::CodeConfig::from_hcl(&content)
   175	                .map_err(|e| anyhow::anyhow!("Failed to parse {}: {}", a3s_config.display(), e))?;
   176	            let mut sc = SafeClawConfig::default();
   177	            sc.models = code_config;
   178	            (sc, Some(a3s_config))
   179	        } else if let Some(config_dir) = dirs::config_dir() {
   180	            let hcl_path = config_dir.join("safeclaw/config.hcl");
   181	            if hcl_path.exists() {
   182	                let content = std::fs::read_to_string(&hcl_path)?;
   183	                tracing::info!("Loading config from {}", hcl_path.display());
   184	                (SafeClawConfig::from_hcl(&content)?, Some(hcl_path))
   185	            } else {
   186	                (SafeClawConfig::default(), None)
   187	            }
   188	        } else {
   189	            (SafeClawConfig::default(), None)
   190	        };
   191	
   192	    // If the primary config has no model providers, merge in .a3s/config.hcl model config.
   193	    // This allows safeclaw.local.hcl to handle gateway/channels while .a3s/config.hcl
   194	    // handles LLM providers вҖ” the two files complement each other.
   195	    if config.models.providers.is_empty() {
   196	        if let Some(a3s_config) = find_a3s_config() {
   197	            if let Ok(content) = std::fs::read_to_string(&a3s_config) {
   198	                if let Ok(code_config) = a3s_code::config::CodeConfig::from_hcl(&content) {
   199	                    if !code_config.providers.is_empty() {
   200	                        tracing::info!("Merging model config from {}", a3s_config.display());
   201	                        config.models = code_config;
   202	                    }
   203	                }
   204	            }
   205	        }
   206	    }
   207	
   208	    match cli.command {
   209	        Commands::Update => {
   210	            return a3s_updater::run_update(&a3s_updater::UpdateConfig {
   211	                binary_name: "safeclaw",
   212	                crate_name: "safeclaw",
   213	                current_version: env!("CARGO_PKG_VERSION"),
   214	                github_owner: "A3S-Lab",
   215	                github_repo: "SafeClaw",
   216	            })
   217	            .await;
   218	        }
   219	        Commands::Gateway { host, port, no_tee } => {
   220	            run_gateway(config, config_path, host, port, !no_tee).await?;
   221	        }
   222	        Commands::Serve { host, port, no_tee } => {
   223	            run_serve(config, config_path, host, port, !no_tee).await?;
   224	        }
   225	        Commands::ServerConfig { output } => {
   226	            generate_gateway_config(&config, output.as_deref())?;
   227	        }
   228	        Commands::Onboard { install_daemon } => {
   229	            run_onboard(install_daemon).await?;
   230	        }
   231	        Commands::Message {
   232	            channel,
   233	            to,
   234	            message,
   235	            gateway_url,
   236	        } => {
   237	            send_message(&channel, &to, &message, &gateway_url).await?;
   238	        }
   239	        Commands::Doctor => {
   240	            run_doctor().await?;
   241	        }
   242	        Commands::Config { default } => {
   243	            show_config(if default { None } else { Some(&config) })?;
   244	        }
   245	    }
   246	
   247	    Ok(())
   248	}
