   250	/// Build the shared agent state used by the agent HTTP/WS router.
   251	///
   252	/// Creates an `AgentEngine` that wraps a3s-code's `SessionManager` in-process,
   253	/// replacing the previous CLI subprocess architecture.
   254	async fn build_agent_state(
   255	    mut code_config: a3s_code::config::CodeConfig,
   256	    skills_config: safeclaw::config::SkillsConfig,
   257	    memory_store: std::sync::Arc<dyn a3s_memory::MemoryStore>,
   258	) -> Result<AgentState> {
   259	    let sessions_dir = AgentSessionStore::default_dir();
   260	    code_config.sessions_dir = Some(sessions_dir.clone());
   261	
   262	    let cwd = std::env::current_dir()
   263	        .unwrap_or_else(|_| std::path::PathBuf::from("/tmp"))
   264	        .to_string_lossy()
   265	        .to_string();
   266	    let tool_executor = std::sync::Arc::new(a3s_code::tools::ToolExecutor::new(cwd));
   267	
   268	    // Build default LLM client from config (None if no providers configured вҖ” that's OK)
   269	    let default_llm = code_config
   270	        .default_llm_config()
   271	        .map(|llm_cfg| a3s_code::llm::create_client_with_config(llm_cfg));
   272	
   273	    if default_llm.is_some() {
   274	        tracing::info!(
   275	            model = code_config.default_model.as_deref().unwrap_or("unknown"),
   276	            "Default LLM client initialized from config"
   277	        );
   278	    } else {
   279	        tracing::info!("No LLM config found вҖ” LLM can be configured via PUT /api/agent/config");
   280	    }
   281	
   282	    // Initialize skill registry
   283	    let skill_registry = std::sync::Arc::new(a3s_code::skills::SkillRegistry::with_builtins());
   284	    let skills_dir = std::path::PathBuf::from(&skills_config.dir);
   285	    if skills_config.auto_load {
   286	        match skill_registry.load_from_dir(&skills_dir) {
   287	            Ok(count) => {
   288	                if count > 0 {
   289	                    tracing::info!(count, dir = %skills_dir.display(), "Loaded skills from directory");
   290	                }
   291	            }
   292	            Err(e) => {
   293	                tracing::debug!("Skills directory not loaded: {}", e);
   294	            }
   295	        }
   296	    }
   297	    tracing::info!(count = skill_registry.len(), "Skill registry initialized");
   298	
   299	    let session_manager = std::sync::Arc::new(
   300	        a3s_code::session::SessionManager::with_persistence(
   301	            default_llm,
   302	            tool_executor,
   303	            &sessions_dir,
   304	        )
   305	        .await
   306	        .context("Failed to create SessionManager")?,
   307	    );
   308	
   309	    // Wire skill registry + manage_skill tool into session manager
   310	    session_manager
   311	        .set_skill_registry(skill_registry, skills_dir)
   312	        .await;
   313	
   314	    // Wire shared memory store so agent's remember_success/remember_failure
   315	    // writes are immediately visible in the UI memory browser
   316	    session_manager.set_memory_store(memory_store).await;
   317	
   318	    let store = std::sync::Arc::new(AgentSessionStore::new(sessions_dir.join("ui-state")));
   319	    let engine = std::sync::Arc::new(
   320	        AgentEngine::new(session_manager, code_config, store)
   321	            .await
   322	            .map_err(|e| anyhow::anyhow!("Failed to create AgentEngine: {}", e))?,
   323	    );
   324	
   325	    Ok(AgentState { engine })
   326	}
