   328	async fn run_gateway(
   329	    config: SafeClawConfig,
   330	    config_path: Option<std::path::PathBuf>,
   331	    host: String,
   332	    port: u16,
   333	    tee_enabled: bool,
   334	) -> Result<()> {
   335	    tracing::info!("Starting SafeClaw runtime");
   336	
   337	    let models = config.models.clone();
   338	    let skills_config = config.skills.clone();
   339	    let lifecycle_config = config.session_lifecycle.clone();
   340	
   341	    // Initialize shared memory store early вҖ” shared between agent runtime and API layer
   342	    let memory_dir = dirs::config_dir()
   343	        .unwrap_or_else(|| std::path::PathBuf::from("."))
   344	        .join("safeclaw")
   345	        .join("memory");
   346	    let memory_store: std::sync::Arc<dyn a3s_memory::MemoryStore> = std::sync::Arc::new(
   347	        a3s_memory::FileMemoryStore::new(memory_dir.clone())
   348	            .await
   349	            .context("Failed to initialize memory store")?,
   350	    );
   351	    tracing::info!(dir = %memory_dir.display(), "Memory store initialized");
   352	
   353	    let gateway = RuntimeBuilder::new()
   354	        .config(config)
   355	        .host(&host)
   356	        .port(port)
   357	        .tee_enabled(tee_enabled)
   358	        .build()?;
   359	
   360	    // Build agent state and wire engine into gateway before start
   361	    let agent_state = build_agent_state(models.clone(), skills_config, memory_store.clone()).await?;
   362	    if let Some(path) = config_path {
   363	        agent_state.engine.set_config_path(path).await;
   364	    }
   365	    gateway.set_agent_engine(agent_state.engine.clone()).await;
   366	
   367	    // Wire agent bus (in-memory by default; NATS if event bridge is configured)
   368	    {
   369	        let provider = a3s_event::MemoryProvider::default();
   370	        let event_bus = std::sync::Arc::new(a3s_event::EventBus::new(provider));
   371	        let agent_bus = std::sync::Arc::new(AgentBus::new(agent_state.engine.clone(), event_bus));
   372	        agent_state.engine.set_bus(agent_bus.clone()).await;
   373	        agent_bus.start();
   374	        tracing::info!("AgentBus started (in-memory provider)");
   375	    }
   376	
   377	    // Start session lifecycle background task
   378	    agent_state
   379	        .engine
   380	        .start_lifecycle_task(lifecycle_config);
   381	
   382	    gateway.start().await?;
   383	
   384	    let gateway = std::sync::Arc::new(gateway);
   385	
   386	    // Build audit state from gateway's shared log and alert monitor
   387	    let audit_state = AuditState {
   388	        log: gateway.global_audit_log().clone(),
   389	        alert_monitor: Some(gateway.alert_monitor().clone()),
   390	        persistence: None,
   391	    };
   392	
   393	    let privacy_state = PrivacyState {
   394	        classifier: std::sync::Arc::new(
   395	            safeclaw::privacy::classifier::Classifier::new(
   396	                safeclaw::config::default_classification_rules(),
   397	                safeclaw::config::SensitivityLevel::Normal,
   398	            )
   399	            .expect("default classifier"),
   400	        ),
   401	        semantic: std::sync::Arc::new(safeclaw::privacy::semantic::SemanticAnalyzer::new()),
   402	    };
   403	
   404	    // Initialize per-channel agent config store
   405	    let channel_config_dir = dirs::config_dir()
   406	        .unwrap_or_else(|| std::path::PathBuf::from("."))
   407	        .join("safeclaw");
   408	    let channel_config_store =
   409	        safeclaw::config::ChannelAgentConfigStore::new(channel_config_dir).await;
   410	
   411	    let engine_for_shutdown = agent_state.engine.clone();
   412	    let app = build_app(
   413	        gateway.clone(),
   414	        agent_state,
   415	        privacy_state,
   416	        audit_state,
   417	        memory_store.clone(),
   418	        channel_config_store,
   419	        &[],
   420	    );
   421	
   422	    let addr: std::net::SocketAddr = format!("{}:{}", host, port)
   423	        .parse()
   424	        .context("Invalid listen address")?;
   425	
   426	    tracing::info!(%addr, "SafeClaw runtime listening");
   427	
   428	    let listener = tokio::net::TcpListener::bind(addr).await?;
   429	    axum::serve(listener, app)
   430	        .with_graceful_shutdown(async {
   431	            tokio::signal::ctrl_c().await.ok();
   432	        })
   433	        .await
   434	        .context("HTTP server error")?;
   435	
   436	    tracing::info!("Shutting down...");
   437	    engine_for_shutdown.shutdown().await;
   438	    gateway.stop().await?;
   439	
   440	    Ok(())
   441	}
