   554	// generate_gateway_config вҖ” output a3s-gateway config for SafeClaw
   555	// ---------------------------------------------------------------------------
   556	
   557	fn generate_gateway_config(
   558	    _config: &SafeClawConfig,
   559	    output: Option<&std::path::Path>,
   560	) -> Result<()> {
   561	    let descriptor = safeclaw::runtime::build_service_descriptor();
   562	    let json = serde_json::to_string_pretty(&descriptor)
   563	        .context("Failed to serialize service descriptor")?;
   564	
   565	    if let Some(path) = output {
   566	        std::fs::write(path, &json)
   567	            .with_context(|| format!("Failed to write service descriptor to {}", path.display()))?;
   568	        println!("Service descriptor written to: {}", path.display());
   569	    } else {
   570	        println!("{}", json);
   571	    }
   572	
   573	    Ok(())
   574	}
