   576	// send_message вҖ” POST to running gateway
   577	// ---------------------------------------------------------------------------
   578	
   579	async fn send_message(channel: &str, to: &str, message: &str, gateway_url: &str) -> Result<()> {
   580	    let client = reqwest::Client::new();
   581	
   582	    // Health check
   583	    let health_url = format!("{}/health", gateway_url);
   584	    let health_resp = client
   585	        .get(&health_url)
   586	        .send()
   587	        .await
   588	        .context("Failed to connect to gateway. Is it running?")?;
   589	
   590	    if !health_resp.status().is_success() {
   591	        anyhow::bail!(
   592	            "Gateway health check failed with status {}",
   593	            health_resp.status()
   594	        );
   595	    }
   596	
   597	    let health: serde_json::Value = health_resp
   598	        .json()
   599	        .await
   600	        .context("Failed to parse health response")?;
   601	    println!(
   602	        "Gateway is healthy (version: {})",
   603	        health["version"].as_str().unwrap_or("unknown")
   604	    );
   605	
   606	    // Send message
   607	    let msg_url = format!("{}/message", gateway_url);
   608	    let body = serde_json::json!({
   609	        "channel": channel,
   610	        "chat_id": to,
   611	        "content": message,
   612	    });
   613	
   614	    let resp = client
   615	        .post(&msg_url)
   616	        .json(&body)
   617	        .send()
   618	        .await
   619	        .context("Failed to send message to gateway")?;
   620	
   621	    let status = resp.status();
   622	    let resp_body: serde_json::Value = resp
   623	        .json()
   624	        .await
   625	        .context("Failed to parse message response")?;
   626	
   627	    if status.is_success() {
   628	        println!(
   629	            "Message sent! ID: {}, Status: {}",
   630	            resp_body["message_id"].as_str().unwrap_or("unknown"),
   631	            resp_body["status"].as_str().unwrap_or("unknown"),
   632	        );
   633	    } else {
   634	        anyhow::bail!(
   635	            "Failed to send message (HTTP {}): {}",
   636	            status,
   637	            resp_body["status"].as_str().unwrap_or("unknown error"),
   638	        );
   639	    }
   640	
   641	    Ok(())
   642	}
