   645	// prompt_input вҖ” interactive stdin helper
   646	// ---------------------------------------------------------------------------
   647	
   648	fn prompt_input(question: &str, default: &str) -> String {
   649	    prompt_input_from(
   650	        question,
   651	        default,
   652	        &mut io::stdin().lock(),
   653	        &mut io::stdout(),
   654	    )
   655	}
   656	
   657	fn prompt_input_from(
   658	    question: &str,
   659	    default: &str,
   660	    reader: &mut dyn BufRead,
   661	    writer: &mut dyn Write,
   662	) -> String {
   663	    if default.is_empty() {
   664	        let _ = write!(writer, "{}: ", question);
   665	    } else {
   666	        let _ = write!(writer, "{} [{}]: ", question, default);
   667	    }
   668	    let _ = writer.flush();
   669	
   670	    let mut input = String::new();
   671	    let _ = reader.read_line(&mut input);
   672	    let trimmed = input.trim();
   673	    if trimmed.is_empty() {
   674	        default.to_string()
   675	    } else {
   676	        trimmed.to_string()
   677	    }
   678	}
   679	
   680	fn prompt_yes_no(question: &str, default_yes: bool) -> bool {
   681	    let default_str = if default_yes { "Y/n" } else { "y/N" };
   682	    let answer = prompt_input(&format!("{} [{}]", question, default_str), "");
   683	    if answer.is_empty() {
   684	        return default_yes;
   685	    }
   686	    matches!(answer.to_lowercase().as_str(), "y" | "yes")
   687	}
