   690	// run_onboard вҖ” interactive setup wizard
   691	// ---------------------------------------------------------------------------
   692	
   693	async fn run_onboard(install_daemon: bool) -> Result<()> {
   694	    println!("SafeClaw Onboarding Wizard");
   695	    println!("=========================");
   696	    println!();
   697	    println!("SafeClaw is a secure personal AI assistant that protects your privacy");
   698	    println!("by running sensitive computations in a Trusted Execution Environment (TEE).");
   699	    println!();
   700	
   701	    // Step 1: Gateway Config
   702	    println!("--- Step 1: Gateway Configuration ---");
   703	    let host = prompt_input("Gateway host", "127.0.0.1");
   704	    let port: u16 = prompt_input("Gateway port", "18790")
   705	        .parse()
   706	        .unwrap_or(18790);
   707	    println!();
   708	
   709	    // Step 2: TEE Configuration
   710	    println!("--- Step 2: TEE Configuration ---");
   711	    let tee_enabled = prompt_yes_no("Enable TEE?", true);
   712	    let mut tee_backend = TeeBackend::A3sBox;
   713	    let mut memory_mb: u32 = 2048;
   714	    let mut cpu_cores: u32 = 2;
   715	
   716	    if tee_enabled {
   717	        let backend_str = prompt_input(
   718	            "TEE backend (a3s_box / intel_sgx / amd_sev / arm_trustzone)",
