   909	fn install_system_daemon(config_path: &std::path::Path) -> Result<()> {
   910	    #[cfg(target_os = "macos")]
   911	    {
   912	        install_launchd_daemon(config_path)?;
   913	    }
   914	    #[cfg(target_os = "linux")]
   915	    {
   916	        install_systemd_daemon(config_path)?;
   917	    }
   918	    #[cfg(not(any(target_os = "macos", target_os = "linux")))]
   919	    {
   920	        let _ = config_path;
   921	        println!("Daemon installation is not supported on this platform.");
   922	    }
   923	    Ok(())
