   926	#[cfg(target_os = "macos")]
   927	fn install_launchd_daemon(config_path: &std::path::Path) -> Result<()> {
   928	    let plist_content = generate_launchd_plist(config_path)?;
   929	    let home = std::env::var("HOME").context("HOME not set")?;
   930	    let agents_dir = PathBuf::from(&home).join("Library/LaunchAgents");
   931	    std::fs::create_dir_all(&agents_dir).with_context(|| {
   932	        format!(
   933	            "Failed to create LaunchAgents directory: {}",
   934	            agents_dir.display()
   935	        )
   936	    })?;
   937	
   938	    let plist_path = agents_dir.join("com.a3s.safeclaw.plist");
   939	    std::fs::write(&plist_path, &plist_content)
   940	        .with_context(|| format!("Failed to write plist: {}", plist_path.display()))?;
   941	
   942	    println!("LaunchAgent installed: {}", plist_path.display());
   943	    println!("Loading daemon...");
   944	
   945	    let status = std::process::Command::new("launchctl")
   946	        .args(["load", "-w"])
   947	        .arg(&plist_path)
   948	        .status()
   949	        .context("Failed to run launchctl")?;
   950	
   951	    if status.success() {
   952	        println!("Daemon loaded successfully.");
   953	    } else {
   954	        println!("Warning: launchctl load returned non-zero exit code.");
   955	    }
   956	
   957	    Ok(())
   958	}
