   960	#[cfg(target_os = "linux")]
   961	fn install_systemd_daemon(config_path: &std::path::Path) -> Result<()> {
   962	    let unit_content = generate_systemd_unit(config_path)?;
   963	    let home = std::env::var("HOME").context("HOME not set")?;
   964	    let units_dir = PathBuf::from(&home).join(".config/systemd/user");
   965	    std::fs::create_dir_all(&units_dir).with_context(|| {
   966	        format!(
   967	            "Failed to create systemd user directory: {}",
   968	            units_dir.display()
   969	        )
   970	    })?;
   971	
   972	    let unit_path = units_dir.join("safeclaw.service");
   973	    std::fs::write(&unit_path, &unit_content)
   974	        .with_context(|| format!("Failed to write unit file: {}", unit_path.display()))?;
   975	
   976	    println!("Systemd user unit installed: {}", unit_path.display());
   977	    println!("Enabling and starting daemon...");
   978	
   979	    let _ = std::process::Command::new("systemctl")
   980	        .args(["--user", "daemon-reload"])
   981	        .status();
   982	    let status = std::process::Command::new("systemctl")
   983	        .args(["--user", "enable", "--now", "safeclaw.service"])
   984	        .status()
   985	        .context("Failed to run systemctl")?;
   986	
   987	    if status.success() {
   988	        println!("Daemon enabled and started.");
   989	    } else {
   990	        println!("Warning: systemctl enable returned non-zero exit code.");
   991	    }
   992	
   993	    Ok(())
   994	}
