    56	/// Build the complete SafeClaw HTTP application
    57	///
    58	/// Merges all module routers, adds CORS middleware, and returns a single
    59	/// `Router` ready to be served by `axum::serve`.
    60	pub fn build_app(
    61	    gateway: Arc<Runtime>,
    62	    agent_state: AgentState,
    63	    privacy_state: PrivacyState,
    64	    audit_state: AuditState,
    65	    memory_store: Arc<dyn MemoryStore>,
    66	    channel_config_store: ChannelAgentConfigStore,
    67	    cors_origins: &[String],
    68	) -> Router {
    69	    let cors = build_cors(cors_origins);
    70	    let gateway_routes = gateway_api_router(gateway.clone(), channel_config_store);
    71	    let memory_routes = memory_api_router(MemoryState { store: memory_store });
    72	
    73	    Router::new()
    74	        .route("/health", get(health_check))
    75	        .route("/.well-known/a3s-service.json", get(service_discovery))
    76	        .merge(gateway_routes)
    77	        .merge(memory_routes)
    78	        .merge(agent_router(agent_state))
    79	        .merge(privacy_router(privacy_state))
    80	        .merge(audit_router(audit_state))
    81	        .layer(cors)
    82	}
