    88	fn gateway_api_router(gateway: Arc<Runtime>, channel_config_store: ChannelAgentConfigStore) -> Router {
    89	    let channel_config_routes = Router::new()
    90	        .route(
    91	            "/api/v1/channels/:channel_id/agent-config",
    92	            get(get_channel_agent_config).patch(update_channel_agent_config),
    93	        )
    94	        .route("/api/v1/channel-agent-configs", get(list_channel_agent_configs))
    95	        .with_state(channel_config_store);
    96	
    97	    Router::new()
    98	        .route("/api/v1/gateway/status", get(gateway_status))
    99	        .route("/api/v1/gateway/sessions", get(gateway_list_sessions))
   100	        .route("/api/v1/gateway/sessions/:id", get(gateway_get_session))
   101	        .route("/api/v1/gateway/message", post(gateway_send_message))
   102	        .route("/api/v1/gateway/webhook/:channel", post(gateway_webhook))
   103	        // Security & observability endpoints
   104	        .route("/api/v1/tee/status", get(tee_status))
   105	        .route("/api/v1/channels", get(list_channels))
   106	        .route("/api/v1/security/overview", get(security_overview))
   107	        .route("/api/v1/taint/entries", get(list_taint_entries))
   108	        // User management endpoints (stub вҖ” Phase 20)
   109	        .route("/api/v1/users", get(list_users).post(create_user))
   110	        .route(
   111	            "/api/v1/users/:id",
   112	            patch(update_user).delete(delete_user),
   113	        )
   114	        .with_state(gateway)
   115	        .merge(channel_config_routes)
   116	}
