   235	async fn gateway_webhook(
   236	    axum::extract::State(gateway): axum::extract::State<Arc<Runtime>>,
   237	    axum::extract::Path(channel): axum::extract::Path<String>,
   238	    body: String,
   239	) -> impl IntoResponse {
   240	    tracing::info!(
   241	        channel = %channel,
   242	        body_len = body.len(),
   243	        body_preview = %body.chars().take(200).collect::<String>(),
   244	        "Webhook received"
   245	    );
   246	
   247	    // Parse the webhook synchronously вҖ” handles decrypt, dedup, ACL
   248	    let parse_result = match gateway.processor().parse_webhook(&channel, &body).await {
   249	        Ok(result) => result,
   250	        Err(e) => {
   251	            return (
   252	                StatusCode::BAD_REQUEST,
   253	                Json(
   254	                    serde_json::json!({"error": {"code": "WEBHOOK_ERROR", "message": e.to_string()}}),
   255	                ),
   256	            );
   257	        }
   258	    };
   259	
   260	    use crate::runtime::processor::WebhookParseResult;
   261	    match parse_result {
   262	        // Challenge must be returned synchronously
   263	        WebhookParseResult::Challenge(response) => {
   264	            if response.outbound.chat_id == "__challenge__" {
   265	                return (
   266	                    StatusCode::OK,
   267	                    Json(serde_json::json!({"challenge": response.outbound.content})),
   268	                );
   269	            }
   270	            (StatusCode::OK, Json(serde_json::json!({"status": "ok"})))
   271	        }
   272	        // Message: return 200 immediately, process with streaming in background
   273	        WebhookParseResult::Message(inbound) => {
   274	            let gw = gateway.clone();
   275	            let ch = channel.clone();
   276	            tokio::spawn(async move {
   277	                let channels = gw.channels().read().await;
   278	                let adapter = match channels.get(&ch) {
   279	                    Some(a) => a.clone(),
   280	                    None => {
   281	                        tracing::warn!(channel = %ch, "No channel adapter registered");
   282	                        return;
   283	                    }
   284	                };
   285	                drop(channels);
   286	
   287	                if let Err(e) = gw
   288	                    .processor()
   289	                    .process_message_streaming(inbound, adapter)
   290	                    .await
   291	                {
   292	                    tracing::error!(channel = %ch, "Streaming processing failed: {}", e);
   293	                }
   294	            });
   295	
   296	            (
   297	                StatusCode::OK,
   298	                Json(serde_json::json!({"status": "accepted"})),
   299	            )
   300	        }
   301	        // Card action: must return updated card JSON synchronously (within 3s)
   302	        WebhookParseResult::CardAction(action) => {
   303	            let channels = gateway.channels().read().await;
   304	            let adapter = match channels.get(&channel) {
   305	                Some(a) => a.clone(),
   306	                None => {
   307	                    tracing::warn!(channel = %channel, "No channel adapter for card action");
   308	                    return (
   309	                        StatusCode::OK,
   310	                        Json(serde_json::json!({"status": "no_adapter"})),
   311	                    );
   312	                }
   313	            };
   314	            drop(channels);
   315	
   316	            match gateway
   317	                .processor()
   318	                .handle_card_action(action, adapter)
   319	                .await
   320	            {
   321	                Ok(_) => (StatusCode::OK, Json(serde_json::json!({}))),
   322	                Err(e) => {
   323	                    tracing::error!(channel = %channel, "Card action handling failed: {}", e);
   324	                    (StatusCode::OK, Json(serde_json::json!({})))
   325	                }
   326	            }
   327	        }
   328	        WebhookParseResult::Ignored => (
   329	            StatusCode::OK,
   330	            Json(serde_json::json!({"status": "ignored"})),
   331	        ),
   332	    }
   333	}
