   469	async fn list_taint_entries(
   470	    axum::extract::State(gateway): axum::extract::State<Arc<Runtime>>,
   471	) -> impl IntoResponse {
   472	    let isolation = gateway.session_manager().isolation();
   473	    let session_ids = isolation.session_ids().await;
   474	    let mut entries = Vec::new();
   475	
   476	    for sid in &session_ids {
   477	        if let Some(guard) = isolation.registry(sid).await {
   478	            let session_entries = guard
   479	                .read(|reg| {
   480	                    reg.entries()
   481	                        .values()
   482	                        .map(|entry| {
   483	                            serde_json::json!({
   484	                                "id": entry.id,
   485	                                "sessionId": sid,
   486	                                "taintType": entry.taint_type,
   487	                                "variantCount": entry.variants.len(),
   488	                                "createdAt": entry.created_at,
   489	                            })
   490	                        })
   491	                        .collect::<Vec<_>>()
   492	                })
   493	                .await;
   494	            if let Some(session_entries) = session_entries {
   495	                entries.extend(session_entries);
   496	            }
   497	        }
   498	    }
   499	
