   505	// =============================================================================
   506	
   507	/// Memory layer вҶ’ MemoryType mapping.
   508	///
   509	/// The UI uses a three-layer model (resources / artifacts / insights) which maps
   510	/// to a3s-memory's `MemoryType` enum:
   511	///   - resources вҶ’ Episodic (raw observations from sessions)
   512	///   - artifacts вҶ’ Semantic + Procedural (structured knowledge & patterns)
   513	///   - insights  вҶ’ items tagged "insight" with high importance (cross-session synthesis)
   514	fn layer_to_filter(layer: &str) -> LayerFilter {
   515	    match layer {
   516	        "resources" => LayerFilter::Types(vec![a3s_memory::MemoryType::Episodic]),
   517	        "artifacts" => LayerFilter::Types(vec![
   518	            a3s_memory::MemoryType::Semantic,
   519	            a3s_memory::MemoryType::Procedural,
   520	        ]),
   521	        "insights" => LayerFilter::Tag("insight".to_string()),
   522	        _ => LayerFilter::Types(vec![]),
   523	    }
   524	}
   525	
   526	enum LayerFilter {
   527	    Types(Vec<a3s_memory::MemoryType>),
   528	    Tag(String),
