   549	/// Serialize a MemoryItem into the JSON shape the UI expects.
   550	fn memory_item_to_json(item: &a3s_memory::MemoryItem) -> serde_json::Value {
   551	    let now = chrono::Utc::now();
   552	    let age_days = (now - item.timestamp).num_days();
   553	    let decay_days = (90 - age_days).max(0);
   554	
   555	    // Taint labels are stored as tags with "taint:" prefix
   556	    let taint_labels: Vec<&str> = item
   557	        .tags
   558	        .iter()
   559	        .filter(|t| t.starts_with("taint:"))
   560	        .map(|t| t.as_str())
   561	        .collect();
   562	
   563	    // Derive layer from memory type
   564	    let layer = match item.memory_type {
   565	        a3s_memory::MemoryType::Episodic => "resources",
   566	        a3s_memory::MemoryType::Semantic | a3s_memory::MemoryType::Procedural => "artifacts",
   567	        a3s_memory::MemoryType::Working => "resources",
   568	    };
   569	
   570	    serde_json::json!({
   571	        "id": item.id,
   572	        "layer": layer,
   573	        "title": item.metadata.get("title").cloned()
   574	            .unwrap_or_else(|| item.content.chars().take(60).collect::<String>()),
   575	        "content": item.content,
   576	        "taintLabels": taint_labels,
   577	        "tags": item.tags,
   578	        "importance": item.importance,
   579	        "memoryType": format!("{:?}", item.memory_type),
   580	        "createdAt": item.timestamp.timestamp_millis(),
   581	        "lastAccessedAt": item.last_accessed
   582	            .map(|t| t.timestamp_millis())
   583	            .unwrap_or_else(|| item.timestamp.timestamp_millis()),
   584	        "decayDays": decay_days,
   585	        "sessionId": item.metadata.get("session_id").cloned(),
   586	    })
   587	}
