   589	/// GET /api/v1/memory/:layer вҖ” list memory entries for a layer
   590	async fn list_memory_layer(
   591	    State(state): State<MemoryState>,
   592	    Path(layer): Path<String>,
   593	    Query(params): Query<MemoryQuery>,
   594	) -> impl IntoResponse {
   595	    let limit = params.limit.unwrap_or(100);
   596	
   597	    // If search query provided, search across all items then filter by layer
   598	    let items = if let Some(ref query) = params.search {
   599	        match state.store.search(query, limit * 3).await {
   600	            Ok(items) => items,
   601	            Err(e) => {
   602	                tracing::warn!("Memory search failed: {}", e);
   603	                return Json(serde_json::json!({
   604	                    "layer": layer, "entries": [], "total": 0
   605	                }));
   606	            }
   607	        }
   608	    } else {
   609	        // Fetch by layer filter
   610	        let result = match layer_to_filter(&layer) {
   611	            LayerFilter::Types(types) => {
   612	                // get_recent returns all types; we filter in-memory
   613	                state.store.get_recent(limit * 3).await
   614	                    .map(|items| items.into_iter()
   615	                        .filter(|i| types.contains(&i.memory_type))
   616	                        .collect::<Vec<_>>())
   617	            }
   618	            LayerFilter::Tag(tag) => {
   619	                state.store.search_by_tags(&[tag], limit).await
   620	            }
   621	        };
   622	        match result {
   623	            Ok(items) => items,
   624	            Err(e) => {
   625	                tracing::warn!("Memory list failed: {}", e);
   626	                return Json(serde_json::json!({
   627	                    "layer": layer, "entries": [], "total": 0
   628	                }));
   629	            }
   630	        }
   631	    };
   632	
   633	    // Filter by layer if we did a search (search returns all types)
   634	    let filtered: Vec<_> = if params.search.is_some() {
   635	        let filter = layer_to_filter(&layer);
   636	        items.into_iter().filter(|item| match &filter {
   637	            LayerFilter::Types(types) => types.contains(&item.memory_type),
   638	            LayerFilter::Tag(tag) => item.tags.contains(tag),
   639	        }).take(limit).collect()
   640	    } else {
   641	        items.into_iter().take(limit).collect()
   642	    };
   643	
   644	    let total = filtered.len();
   645	    let entries: Vec<_> = filtered.iter().map(memory_item_to_json).collect();
   646	
   647	    Json(serde_json::json!({
   648	        "layer": layer,
   649	        "entries": entries,
   650	        "total": total,
   651	    }))
   652	}
