   675	/// DELETE /api/v1/memory/batch вҖ” batch delete memory entries
   676	async fn memory_batch_delete(
   677	    State(state): State<MemoryState>,
   678	    Json(body): Json<serde_json::Value>,
   679	) -> impl IntoResponse {
   680	    let ids: Vec<String> = body
   681	        .get("ids")
   682	        .and_then(|v| serde_json::from_value(v.clone()).ok())
   683	        .unwrap_or_default();
   684	
   685	    if ids.is_empty() {
   686	        return (
   687	            StatusCode::BAD_REQUEST,
   688	            Json(serde_json::json!({ "status": "error", "message": "No ids provided" })),
   689	        );
   690	    }
   691	
   692	    let mut deleted = 0u32;
   693	    let mut errors = 0u32;
   694	    for id in &ids {
   695	        match state.store.delete(id).await {
   696	            Ok(()) => deleted += 1,
   697	            Err(e) => {
   698	                tracing::warn!(id = %id, "Batch delete failed for entry: {}", e);
   699	                errors += 1;
   700	            }
   701	        }
   702	    }
   703	
   704	    tracing::info!(deleted, errors, "Batch memory delete completed");
   705	    (
   706	        StatusCode::OK,
   707	        Json(serde_json::json!({ "status": "ok", "deleted": deleted, "errors": errors })),
   708	    )
   709	}
