   711	/// GET /api/v1/memory/stats вҖ” memory statistics across all layers
   712	async fn memory_stats(State(state): State<MemoryState>) -> impl IntoResponse {
   713	    // Fetch all items to compute stats
   714	    let all_items = state.store.get_recent(10000).await.unwrap_or_default();
   715	    let now = chrono::Utc::now();
   716	
   717	    let mut resources = 0u32;
   718	    let mut artifacts = 0u32;
   719	    let mut insights = 0u32;
   720	    let mut imp_resources = 0f64;
   721	    let mut imp_artifacts = 0f64;
   722	    let mut imp_insights = 0f64;
   723	    let mut expiring_7 = 0u32;
   724	    let mut expiring_30 = 0u32;
   725	    let mut tainted = 0u32;
   726	
   727	    for item in &all_items {
   728	        let age_days = (now - item.timestamp).num_days();
   729	        let decay_days = (90 - age_days).max(0);
   730	        let is_insight = item.tags.iter().any(|t| t == "insight");
   731	        let has_taint = item.tags.iter().any(|t| t.starts_with("taint:"));
   732	
   733	        if has_taint {
   734	            tainted += 1;
   735	        }
   736	        if decay_days <= 7 {
   737	            expiring_7 += 1;
   738	        } else if decay_days <= 30 {
   739	            expiring_30 += 1;
   740	        }
   741	
   742	        if is_insight {
   743	            insights += 1;
   744	            imp_insights += item.importance as f64;
   745	        } else {
   746	            match item.memory_type {
   747	                a3s_memory::MemoryType::Episodic | a3s_memory::MemoryType::Working => {
   748	                    resources += 1;
   749	                    imp_resources += item.importance as f64;
   750	                }
   751	                a3s_memory::MemoryType::Semantic | a3s_memory::MemoryType::Procedural => {
   752	                    artifacts += 1;
   753	                    imp_artifacts += item.importance as f64;
   754	                }
   755	            }
   756	        }
   757	    }
   758	
   759	    let avg = |sum: f64, count: u32| {
   760	        if count == 0 { 0.0 } else { sum / count as f64 }
   761	    };
   762	
   763	    Json(serde_json::json!({
   764	        "layers": { "resources": resources, "artifacts": artifacts, "insights": insights },
   765	        "avgImportance": {
   766	            "resources": avg(imp_resources, resources),
   767	            "artifacts": avg(imp_artifacts, artifacts),
   768	            "insights": avg(imp_insights, insights),
   769	        },
   770	        "expiringIn7Days": expiring_7,
   771	        "expiringIn30Days": expiring_30,
   772	        "tainted": tainted,
   773	        "total": all_items.len(),
   774	    }))
   775	}
