   789	/// GET /api/v1/memory/export вҖ” export memory entries as JSON or CSV
   790	async fn memory_export(
   791	    State(state): State<MemoryState>,
   792	    Query(params): Query<ExportQuery>,
   793	) -> impl IntoResponse {
   794	    let all_items = state.store.get_recent(10000).await.unwrap_or_default();
   795	
   796	    // Filter by layer if specified
   797	    let items: Vec<_> = if let Some(ref layer) = params.layer {
   798	        let filter = layer_to_filter(layer);
   799	        all_items
   800	            .into_iter()
   801	            .filter(|item| match &filter {
   802	                LayerFilter::Types(types) => types.contains(&item.memory_type),
   803	                LayerFilter::Tag(tag) => item.tags.contains(tag),
   804	            })
   805	            .collect()
   806	    } else {
   807	        all_items
   808	    };
   809	
   810	    if params.format == "csv" {
   811	        let mut csv = String::from("id,title,content,tags,importance,memoryType,createdAt\n");
   812	        for item in &items {
   813	            let title = item
   814	                .metadata
   815	                .get("title")
   816	                .cloned()
   817	                .unwrap_or_else(|| item.content.chars().take(60).collect());
   818	            // Escape CSV fields
   819	            let escape = |s: &str| format!("\"{}\"", s.replace('"', "\"\""));
   820	            csv.push_str(&format!(
   821	                "{},{},{},{},{},{:?},{}\n",
   822	                item.id,
   823	                escape(&title),
   824	                escape(&item.content),
   825	                escape(&item.tags.join(";")),
   826	                item.importance,
   827	                item.memory_type,
   828	                item.timestamp.to_rfc3339(),
   829	            ));
   830	        }
   831	        (
   832	            StatusCode::OK,
   833	            [(header::CONTENT_TYPE, "text/csv; charset=utf-8")],
   834	            csv,
   835	        )
   836	            .into_response()
   837	    } else {
   838	        let entries: Vec<_> = items.iter().map(memory_item_to_json).collect();
   839	        let json = serde_json::to_string_pretty(&serde_json::json!({
   840	            "exported_at": chrono::Utc::now().to_rfc3339(),
   841	            "count": entries.len(),
   842	            "layer": params.layer,
   843	            "entries": entries,
   844	        }))
   845	        .unwrap_or_default();
   846	        (
   847	            StatusCode::OK,
   848	            [(header::CONTENT_TYPE, "application/json; charset=utf-8")],
   849	            json,
   850	        )
   851	            .into_response()
   852	    }
   853	}
