   914	fn build_cors(origins: &[String]) -> CorsLayer {
   915	    let cors = CorsLayer::new()
   916	        .allow_methods([
   917	            Method::GET,
   918	            Method::POST,
   919	            Method::PATCH,
   920	            Method::PUT,
   921	            Method::DELETE,
   922	            Method::OPTIONS,
   923	        ])
   924	        .allow_headers([header::CONTENT_TYPE, header::AUTHORIZATION, header::ACCEPT]);
   925	
   926	    if origins.is_empty() {
   927	        cors.allow_origin(Any)
   928	    } else {
   929	        let parsed: Vec<_> = origins.iter().filter_map(|o| o.parse().ok()).collect();
   930	        cors.allow_origin(parsed)
   931	    }
   932	}
