    58	
    59	/// SafeClaw runtime server вҖ” orchestrates lifecycle and infrastructure.
    60	///
    61	/// Message processing is owned by the embedded `MessageProcessor`.
    62	pub struct Runtime {
    63	    config: SafeClawConfig,
    64	    state: Arc<RwLock<RuntimeState>>,
    65	    session_manager: Arc<SessionManager>,
    66	    channels: Arc<RwLock<HashMap<String, Arc<dyn ChannelAdapter>>>>,
    67	    event_tx: mpsc::Sender<crate::channels::ChannelEvent>,
    68	    event_rx: Arc<RwLock<Option<mpsc::Receiver<crate::channels::ChannelEvent>>>>,
    69	    /// Global audit log shared with the REST API
    70	    global_audit_log: Arc<RwLock<AuditLog>>,
    71	    /// Centralized audit event bus
    72	    audit_bus: Arc<AuditEventBus>,
    73	    /// Alert monitor for rate-based anomaly detection
    74	    alert_monitor: Arc<AlertMonitor>,
    75	    /// Message processing pipeline
    76	    processor: Arc<MessageProcessor>,
    77	}
    78	
    79	impl Runtime {
    80	    /// Create a new runtime with the given configuration.
    81	    pub fn new(config: SafeClawConfig) -> Result<Self> {
    82	        let (event_tx, event_rx) = mpsc::channel(1000);
    83	
    84	        let audit_capacity = config.audit.bus_capacity;
    85	        let global_audit_log = Arc::new(RwLock::new(AuditLog::new(audit_capacity)));
    86	        let audit_bus = Arc::new(AuditEventBus::new(audit_capacity, global_audit_log.clone()));
    87	        let alert_monitor = Arc::new(AlertMonitor::new(config.audit.alert.clone()));
    88	
    89	        let session_manager = Arc::new(SessionManager::new(config.tee.clone(), audit_bus.clone()));
    90	
    91	        // Regex-only classifier вҖ” for synchronous redaction helpers
    92	        let classifier = Arc::new(
    93	            Classifier::new(config.privacy.rules.clone(), config.privacy.default_level)
    94	                .map_err(|e| Error::Privacy(format!("Failed to create classifier: {}", e)))?,
    95	        );
    96	
    97	        // Full composite chain (regex + semantic) вҖ” for routing decisions
    98	        let composite = Arc::new({
    99	            let regex =
   100	                RegexBackend::new(config.privacy.rules.clone(), config.privacy.default_level)
   101	                    .map_err(|e| Error::Privacy(format!("Failed to build regex backend: {}", e)))?;
   102	            let semantic = SemanticBackend::new(SemanticAnalyzer::new());
   103	            CompositeClassifier::new(vec![Box::new(regex), Box::new(semantic)])
   104	        });
   105	
   106	        let policy_engine = Arc::new(PolicyEngine::new());
   107	
   108	        let session_router = Arc::new(SessionRouter::new(
   109	            session_manager.clone(),
   110	            classifier,
   111	            composite,
   112	            policy_engine,
   113	        ));
   114	
   115	        let processor = Arc::new(MessageProcessor::new(
   116	            session_router,
   117	            session_manager.clone(),
   118	            config.channels.feishu.clone(),
   119	        ));
   120	
   121	        Ok(Self {
   122	            config,
   123	            state: Arc::new(RwLock::new(RuntimeState::Stopped)),
   124	            session_manager,
   125	            channels: Arc::new(RwLock::new(HashMap::new())),
   126	            event_tx,
   127	            event_rx: Arc::new(RwLock::new(Some(event_rx))),
   128	            global_audit_log,
   129	            audit_bus,
   130	            alert_monitor,
   131	            processor,
   132	        })
   133	    }
