   135	    // -----------------------------------------------------------------------
   136	    // Lifecycle
   137	    // -----------------------------------------------------------------------
   138	
   139	    pub async fn state(&self) -> RuntimeState {
   140	        *self.state.read().await
   141	    }
   142	
   143	    pub async fn start(&self) -> Result<()> {
   144	        let mut state = self.state.write().await;
   145	        if *state != RuntimeState::Stopped {
   146	            return Err(Error::Runtime("Runtime already running".to_string()));
   147	        }
   148	        *state = RuntimeState::Starting;
   149	        drop(state);
   150	
   151	        tracing::info!("Starting SafeClaw runtime");
   152	
   153	        // Initialize TEE subsystem
   154	        if self.config.tee.enabled {
