   297	    pub async fn stop(&self) -> Result<()> {
   298	        let mut state = self.state.write().await;
   299	        if *state != RuntimeState::Running {
   300	            return Ok(());
   301	        }
   302	        *state = RuntimeState::ShuttingDown;
   303	        drop(state);
   304	
   305	        tracing::info!("Stopping SafeClaw runtime");
   306	
   307	        let channels: Vec<Arc<dyn ChannelAdapter>> = {
   308	            let channels = self.channels.read().await;
   309	            channels.values().cloned().collect()
   310	        };
   311	        for channel in channels {
   312	            if let Err(e) = channel.stop().await {
   313	                tracing::warn!("Failed to stop channel {}: {}", channel.name(), e);
   314	            }
   315	        }
   316	
   317	        if self.config.tee.enabled {
   318	            self.session_manager.shutdown_tee().await?;
   319	        }
   320	
   321	        *self.state.write().await = RuntimeState::Stopped;
   322	        tracing::info!("SafeClaw runtime stopped");
   323	
   324	        Ok(())
   325	    }
