   376	    async fn start_event_loop(&self) {
   377	        let event_rx = self.event_rx.write().await.take();
   378	        if let Some(mut rx) = event_rx {
   379	            let processor = self.processor.clone();
   380	            let channels = self.channels.clone();
   381	
   382	            tokio::spawn(async move {
   383	                while let Some(event) = rx.recv().await {
   384	                    if let Err(e) = processor.handle_channel_event(event, &channels).await {
   385	                        tracing::error!("Error handling event: {}", e);
   386	                    }
   387	                }
   388	            });
   389	        }
   390	    }
