   530	/// Try to detect the ngrok public URL by querying the local ngrok API.
   531	/// Returns `None` if ngrok is not running or the API is unreachable.
   532	async fn detect_ngrok_url() -> Option<String> {
   533	    let client = reqwest::Client::builder()
   534	        .timeout(std::time::Duration::from_secs(1))
   535	        .build()
   536	        .ok()?;
   537	
   538	    let resp = client
   539	        .get("http://127.0.0.1:4040/api/tunnels")
   540	        .send()
   541	        .await
   542	        .ok()?;
   543	
   544	    let body: serde_json::Value = resp.json().await.ok()?;
   545	    // Prefer https tunnel
   546	    body.get("tunnels")?
   547	        .as_array()?
   548	        .iter()
   549	        .filter_map(|t| t.get("public_url").and_then(|u| u.as_str()))
   550	        .find(|u| u.starts_with("https://"))
   551	        .or_else(|| {
   552	            body.get("tunnels")?
   553	                .as_array()?
   554	                .first()?
   555	                .get("public_url")?
   556	                .as_str()
   557	        })
   558	        .map(|s| s.to_string())
   559	}
